sections.body:
In this section, you can learn how to connect to your deployment and run
the sample query against the indexed collections in the `sample_training` database.

The following query searches both the `companies` and
`inspections` collections for the term `mobile` in the `name`
and `business_name` fields respectively.

Basic Example

This query uses the following stages:

- [$search](pipe.$search) to search for companies that include `mobile`
  in the name.

- [$unionWith](manual/reference/operator/aggregation/unionWith) to do the following:

  - Use [$search](pipe.$search) stage in the sub-pipeline to
    search for inspections of companies that include `mobile`
    in the name.

  - Perform a union of documents from the `companies` and
    documents from the `inspections` collections.

- [$set](manual/reference/operator/aggregation/set) stage to add a new field named `source` that
  identifies the collection of the output documents.

  - [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `3`
    results from each collection.

  - [$project](manual/reference/operator/aggregation/project) stage to:

    - Include only the specified  fields in the results.

    - Add a field named `score`.

```c
#include <mongoc/mongoc.h>
#include <stdio.h>

int main(int argc, char *argv[]) {
    mongoc_client_t *client;
    mongoc_collection_t *collection;
    mongoc_cursor_t *cursor;
    bson_error_t error;
    bson_t *pipeline;
    const bson_t *doc;
    char *str;

    /* Initialize the MongoDB C Driver. */
    mongoc_init();

    /* Connect to your MongoDB deployment. */
    client = mongoc_client_new("<connection-string>");
    collection = mongoc_client_get_collection(client, "sample_training", "companies");

    if (!client) {
        fprintf(stderr, "Failed to create client.\n");
        return 1;
    }

    /* Build the aggregation pipeline */
    pipeline = BCON_NEW (
        "pipeline", "[",
            "{",
                "$search", "{",
                    "text", "{",
                        "query", "Mobile",
                        "path", "name",
                    "}",
                "}",
            "}",
            "{",
                "$project", "{",
                    "score", "{", "$meta", "searchScore", "}",
                    "_id", BCON_INT32(0),
                    "number_of_employees", BCON_INT32(1),
                    "founded_year", BCON_INT32(1),
                    "name", BCON_INT32(1),
                "}",
            "}",
            "{",
                "$set", "{",
                    "source", "companies",
                "}",
            "}",
            "{",
                "$limit", BCON_INT32(3),
            "}",
            "{",
                "$unionWith", "{",
                    "coll", "inspections",
                    "pipeline", "[",
                        "{",
                            "$search", "{",
                                "text", "{",
                                    "query", "Mobile",
                                    "path", "business_name",
                                "}",
                            "}",
                        "}",
                        "{",
                            "$set", "{",
                                "source", "inspections",
                            "}",
                        "}",
                        "{",
                            "$project", "{",
                                "score", "{", "$meta", "searchScore", "}",
                                "source", BCON_INT32(1),
                                "_id", BCON_INT32(0),
                                "business_name", BCON_INT32(1),
                                "address", BCON_INT32(1),
                            "}",
                        "}",
                        "{",
                            "$limit", BCON_INT32(3),
                        "}",
                        "{",
                            "$sort", "{",
                                "score", BCON_INT32(-1),
                            "}",
                        "}",
                    "]",
                "}",
            "}",
        "]"
    );

    /* Run the aggregation pipeline */
    cursor = mongoc_collection_aggregate(
        collection, MONGOC_QUERY_NONE, pipeline, NULL, NULL);

    /* Print the results */
    while (mongoc_cursor_next(cursor, &doc)) {
        str = bson_as_canonical_extended_json(doc, NULL);
        printf("%s\n", str);
        bson_free(str);
    }

    if (mongoc_cursor_error(cursor, &error)) {
        fprintf(stderr, "Cursor Failure: %s\n", error.message);
    }

    /* Clean up. */
    bson_destroy(pipeline);
    mongoc_cursor_destroy(cursor);
    mongoc_collection_destroy(collection);
    mongoc_client_destroy(client);
    mongoc_cleanup();

    return 0;
}

```

Facet Example

This query uses the following stages:

- [$search](pipe.$search) to search for companies that include `mobile`
  in the name.

- [$project](manual/reference/operator/aggregation/project) stage to:

  - Include only the specified  fields in the results.

  - Add a field named `score`.

- [$addFields](manual/reference/operator/aggregation/addFields) stage to add the following new fields:

  - A new field named `source` that identifies the collection of the
    output documents.

  - A field name `source_count` that shows a count of the output
    documents.

- [$unionWith](manual/reference/operator/aggregation/unionWith) to do the following:

  - Use [$search](pipe.$search) stage in the sub-pipeline to
    search for inspections of companies that include `mobile`
    in the name.

  - Perform a union of documents from the `companies` and
    documents from the `inspections` collections.

- [$project](manual/reference/operator/aggregation/project) stage to:

  - Include only the specified  fields in the results.

  - Add a field named `score`.

- [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `3` results from
  each collection.

- [$set](manual/reference/operator/aggregation/set) stage to add the following new fields:

  - A new field named `source` that identifies the collection of the
    output documents.

  - A new field named `source_count` that shows a count of the
    output documents.

```c
#include <mongoc/mongoc.h>
#include <stdio.h>

int main(int argc, char *argv[]) {
    mongoc_client_t *client;
    mongoc_collection_t *collection;
    mongoc_cursor_t *cursor;
    bson_error_t error;
    bson_t *pipeline;
    const bson_t *doc;
    char *str;

    /* Initialize the MongoDB C Driver. */
    mongoc_init();

    /* Connect to your MongoDB deployment. */
    client = mongoc_client_new("<connection-string>");
    collection = mongoc_client_get_collection(client, "sample_training", "companies");

    if (!client) {
        fprintf(stderr, "Failed to create client.\n");
        return 1;
    }

    /* Build the aggregation pipeline */
    pipeline = BCON_NEW (
        "pipeline", "[",
            "{",
                "$search", "{",
                    "text", "{",
                        "query", "Mobile",
                        "path", "name",
                        "score", "{", 
                            "boost", "{", 
                                "value", BCON_DOUBLE(1.6),
                            "}",
                        "}",
                    "}",
                "}",
            "}",
            "{",
                "$project", "{",
                    "score", "{", "$meta", "searchScore", "}",
                    "_id", BCON_INT32(0),
                    "number_of_employees", BCON_INT32(1),
                    "founded_year", BCON_INT32(1),
                    "name", BCON_INT32(1),
                "}",
            "}",
            "{",
                "$addFields", "{",
                    "source", "companies",
                    "source_count", "$$SEARCH_META.count.lowerBound",
                "}",
            "}",
            "{",
                "$limit", BCON_INT32(3),
            "}",
            "{",
                "$unionWith", "{",
                    "coll", "inspections",
                    "pipeline", "[",
                        "{",
                            "$search", "{",
                                "text", "{",
                                    "query", "mobile",
                                    "path", "business_name",
                                "}",
                            "}",
                        "}",
                        "{",
                            "$project", "{",
                                "score", "{", "$meta", "searchScore", "}",
                                "business_name", BCON_INT32(1),
                                "address", BCON_INT32(1),
                                "_id", BCON_INT32(0),
                            "}",
                        "}",
                        "{",
                            "$limit", BCON_INT32(3),
                        "}",
                        "{",
                            "$set", "{",
                                "source", "inspections",
                                "source_count", "$$SEARCH_META.count.lowerBound",
                            "}",
                        "}",
                        "{",
                            "$sort", "{",
                                "score", BCON_INT32(-1),
                            "}",
                        "}",
                    "]",
                "}",
            "}",
            "{",
                "$facet", "{",
                    "allDocs", "[", "]",
                    "totalCount", "[",
                        "{",
                            "$group", "{",
                                "_id", "$source",
                                "firstCount", "{", "$first", "$source_count", "}",
                            "}",
                        "}",
                        "{",
                            "$project", "{",
                                "totalCount", "{", "$sum", "$firstCount", "}",
                            "}",
                        "}",
                    "]",
                "}",
            "}",
        "]"
    );

    /* Run the aggregation pipeline */
    cursor = mongoc_collection_aggregate(
        collection, MONGOC_QUERY_NONE, pipeline, NULL, NULL);

    /* Print the results */
    while (mongoc_cursor_next(cursor, &doc)) {
        str = bson_as_canonical_extended_json(doc, NULL);
        printf("%s\n", str);
        bson_free(str);
    }

    if (mongoc_cursor_error(cursor, &error)) {
        fprintf(stderr, "Cursor Failure: %s\n", error.message);
    }

    /* Clean up. */
    bson_destroy(pipeline);
    mongoc_cursor_destroy(cursor);
    mongoc_collection_destroy(collection);
    mongoc_client_destroy(client);
    mongoc_cleanup();

    return 0;
}

```

Ensure that your connection string includes your database user's
credentials. To learn more, see [Driver](connect-via-driver).

Edit the `CMakeLists.txt` file created in the previous section
to resemble the following code:

```c
cmake_minimum_required(VERSION 3.11)
project(search-with-unionwith LANGUAGES C)
add_executable (unionwith.out search-with-unionwith-query.c)
find_package(mongoc <version> REQUIRED)
target_link_libraries(unionwith.out mongoc::mongoc)
```

