In this section, you can learn how to connect to your deployment and run
the sample query against the indexed collections in the `sample_training` database.

The following query searches both the `companies` and
`inspections` collections for the term `mobile` in the `name`
and `business_name` fields respectively.

Basic Example

This query uses the following stages:

- [$search](pipe.$search) to search for companies that include `mobile`
  in the name.

- [$unionWith](manual/reference/operator/aggregation/unionWith) to do the following:

  - Use [$search](pipe.$search) stage in the sub-pipeline to
    search for inspections of companies that include `mobile`
    in the name.

  - Perform a union of documents from the `companies` and
    documents from the `inspections` collections.

- [$set](manual/reference/operator/aggregation/set) stage to add a new field named `source` that
  identifies the collection of the output documents.

  - [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `3`
    results from each collection.

  - [$project](manual/reference/operator/aggregation/project) stage to:

    - Include only the specified  fields in the results.

    - Add a field named `score`.

```csharp
using MongoDB.Bson;
using MongoDB.Driver;
using MongoDB.Driver.Search;

public class Program
{
    public static void Main(string[] args)
    {
        // connect to your MongoDB deployment
        string connectionString = "<connection-string>";
        var client = new MongoClient(connectionString);

        // define namespace
        var database = client.GetDatabase("sample_training");
        var collection = database.GetCollection<BsonDocument>("companies");

        // define pipeline stage
        var searchStage1 = new BsonDocument("$search", new BsonDocument{{ "text", new BsonDocument
            {{ "query", "Mobile" },{ "path", "name" }}
        }});
        var projectStage1 = new BsonDocument("$project", new BsonDocument{
            { "score", new BsonDocument("$meta", "searchScore") },
            { "_id", 0 },{ "number_of_employees", 1 },{ "founded_year", 1 },{ "name", 1 }
        });
        var setStage1 = new BsonDocument("$set", new BsonDocument{{ "source", "companies" }});
        var limitStage1 = new BsonDocument("$limit", 3);

        // define subpipeline
        var searchStage2 = new BsonDocument("$search", new BsonDocument{{ "text", new BsonDocument
            {{ "query", "Mobile" },{ "path", "business_name" }}
        }});
        var setStage2 = new BsonDocument("$set", new BsonDocument{ { "source", "inspections" } });
        var projectStage2 = new BsonDocument("$project", new BsonDocument{
            { "score", new BsonDocument("$meta", "searchScore") }, 
            { "source", 1 }, { "_id", 0 }, { "business_name", 1 }, { "address", 1 }
        });
        var limitStage2 = new BsonDocument("$limit", 3);
        var sortStage2 = new BsonDocument("$sort", new BsonDocument{{ "score", -1 }});
        var unionWithPipeline = new List<BsonDocument>{searchStage2, setStage2, projectStage2, limitStage2, sortStage2};
        var unionWithStage = new BsonDocument("$unionWith", new BsonDocument
        {
            { "coll", "inspections" },
            { "pipeline", new BsonArray(unionWithPipeline) }
        });
        var aggregationPipeline = new List<BsonDocument> {searchStage1, projectStage1, setStage1, limitStage1,unionWithStage};

        // run pipeline
        var result = collection.Aggregate<BsonDocument>(aggregationPipeline).ToList();

        //print results
        foreach (var document in result)
        {
            Console.WriteLine(document);
        }
    }
}

```

Facet Example

This query uses the following stages:

- [$search](pipe.$search) to search for companies that include `mobile`
  in the name.

- [$project](manual/reference/operator/aggregation/project) stage to:

  - Include only the specified  fields in the results.

  - Add a field named `score`.

- [$addFields](manual/reference/operator/aggregation/addFields) stage to add the following new fields:

  - A new field named `source` that identifies the collection of the
    output documents.

  - A field name `source_count` that shows a count of the output
    documents.

- [$unionWith](manual/reference/operator/aggregation/unionWith) to do the following:

  - Use [$search](pipe.$search) stage in the sub-pipeline to
    search for inspections of companies that include `mobile`
    in the name.

  - Perform a union of documents from the `companies` and
    documents from the `inspections` collections.

- [$project](manual/reference/operator/aggregation/project) stage to:

  - Include only the specified  fields in the results.

  - Add a field named `score`.

- [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `3` results from
  each collection.

- [$set](manual/reference/operator/aggregation/set) stage to add the following new fields:

  - A new field named `source` that identifies the collection of the
    output documents.

  - A new field named `source_count` that shows a count of the
    output documents.

```csharp
using MongoDB.Bson;
using MongoDB.Driver;

public class Program
{
    public static void Main(string[] args)
    {
        // connect to your MongoDB deployment
        var client = new MongoClient("<connection-string>");

        // define namespace
        var database = client.GetDatabase("sample_training");
        var collection = database.GetCollection<BsonDocument>("companies");

        // define pipeline
        var pipeline = new BsonDocument[]
        {
        new BsonDocument("$search", new BsonDocument{
          { "text", new BsonDocument{
            { "query", "mobile" }, { "path", "name" },
            { "score", new BsonDocument{
                { "boost", new BsonDocument{ { "value", 1.6 } }}
            }}
          }}
        }),
        new BsonDocument("$project", new BsonDocument{
          { "score", new BsonDocument("$meta", "searchScore") },
          { "_id", 0 }, 
          { "number_of_employees", 1 }, { "founded_year", 1 }, { "name", 1 }
        }),
        new BsonDocument("$addFields", new BsonDocument{
          { "source", "companies" },
          { "source_count", "$$SEARCH_META.count.lowerBound" }
        }),
        new BsonDocument("$limit", 3),
        new BsonDocument("$unionWith", new BsonDocument{
          { "coll", "inspections" },
          { "pipeline", new BsonArray{
            new BsonDocument("$search", new BsonDocument{
                { "text", new BsonDocument{
                  { "query", "mobile" },
                  { "path", "business_name" }
                }}
            }),
            new BsonDocument("$project", new BsonDocument{
                { "score", new BsonDocument("$meta", "searchScore") },
                { "business_name", 1 }, { "address", 1 }, { "_id", 0 }
            }),
            new BsonDocument("$limit", 3),
            new BsonDocument("$set", new BsonDocument{
                { "source", "inspections" },
                { "source_count", "$$SEARCH_META.count.lowerBound" }
            }),
            new BsonDocument("$sort", new BsonDocument{
                { "score", -1 }
            })
          }}
        }),
        new BsonDocument("$facet", new BsonDocument{
          { "allDocs", new BsonArray() },
          { "totalCount", new BsonArray{
            new BsonDocument("$group", new BsonDocument{
                { "_id", "$source" },
                { "firstCount", new BsonDocument("$first", "$source_count") }
            }),
            new BsonDocument("$project", new BsonDocument{
                { "totalCount", new BsonDocument("$sum", "$firstCount") }
            })
          }}
        })
        };

        // run pipeline
        var result = collection.Aggregate<BsonDocument>(pipeline).ToList();

        //print results
        foreach (var document in result)
        {
            Console.WriteLine(document);
        }
    }
}

```

Ensure that your connection string includes your database user's
credentials. To learn more, see [Driver](connect-via-driver).

