In this section, you can learn how to connect to your deployment and run
the sample query against the indexed collections in the `sample_training` database.

The following query searches both the `companies` and
`inspections` collections for the term `mobile` in the `name`
and `business_name` fields respectively.

Basic Example

This query uses the following stages:

- [$search](pipe.$search) to search for companies that include `mobile`
  in the name.

- [$unionWith](manual/reference/operator/aggregation/unionWith) to do the following:

  - Use [$search](pipe.$search) stage in the sub-pipeline to
    search for inspections of companies that include `mobile`
    in the name.

  - Perform a union of documents from the `companies` and
    documents from the `inspections` collections.

- [$set](manual/reference/operator/aggregation/set) stage to add a new field named `source` that
  identifies the collection of the output documents.

  - [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `3`
    results from each collection.

  - [$project](manual/reference/operator/aggregation/project) stage to:

    - Include only the specified  fields in the results.

    - Add a field named `score`.

```cpp
#include <iostream>

#include <bsoncxx/builder/basic/document.hpp>
#include <bsoncxx/builder/basic/array.hpp>
#include <bsoncxx/json.hpp>
#include <mongocxx/client.hpp>
#include <mongocxx/instance.hpp>
#include <mongocxx/uri.hpp>
#include <mongocxx/pipeline.hpp>

using bsoncxx::builder::basic::kvp;
using bsoncxx::builder::basic::make_document;
using bsoncxx::builder::basic::make_array;

int main() {
    // Initialize the MongoDB C++ driver
    mongocxx::instance instance{};

    // Connect to your MongoDB deployment
    mongocxx::uri uri("<connection-string>");
    mongocxx::client client(uri);

    auto db = client["sample_training"];
    auto collection = db["companies"];

    // Build the aggregation pipeline
    mongocxx::pipeline pipeline{};

    // $search stage
    pipeline.append_stage(make_document(
        kvp("$search", make_document(
            kvp("text", make_document(
                kvp("query", "Mobile"),
                kvp("path", "name")
            ))
        ))
    ));

    // $project stage
    pipeline.append_stage(make_document(
        kvp("$project", make_document(
            kvp("score", make_document(kvp("$meta", "searchScore"))),
            kvp("_id", 0),
            kvp("number_of_employees", 1),
            kvp("founded_year", 1),
            kvp("name", 1)
        ))
    ));

    // $set stage to add source
    pipeline.append_stage(make_document(
        kvp("$set", make_document(
            kvp("source", "companies")
        ))
    ));

    // $limit stage
    pipeline.append_stage(make_document(
        kvp("$limit", 3)
    ));

    // Create the lookup pipeline for the $unionWith stage
    auto lookup_pipeline = mongocxx::pipeline{};

    lookup_pipeline.append_stage(make_document(
        kvp("$search", make_document(
            kvp("text", make_document(
                kvp("query", "Mobile"),
                kvp("path", "business_name")
            ))
        ))
    ));

    lookup_pipeline.append_stage(make_document(
        kvp("$set", make_document(
            kvp("source", "inspections")
        ))
    ));

    lookup_pipeline.append_stage(make_document(
        kvp("$project", make_document(
            kvp("score", make_document(kvp("$meta", "searchScore"))),
            kvp("source", 1),
            kvp("_id", 0),
            kvp("business_name", 1),
            kvp("address", 1)
        ))
    ));

    lookup_pipeline.append_stage(make_document(
        kvp("$limit", 3)
    ));

    lookup_pipeline.append_stage(make_document(
        kvp("$sort", make_document(
            kvp("score", -1)
        ))
    ));

    // Add $unionWith stage to the main pipeline
    pipeline.append_stage(make_document(
        kvp("$unionWith", make_document(
            kvp("coll", "inspections"),
            kvp("pipeline", lookup_pipeline.view_array())
        ))
    ));

    try {
        // Run the aggregation pipeline and print results
        auto cursor = collection.aggregate(pipeline);

        // Process and print the results
        for (auto&& doc : cursor) {
            std::cout << bsoncxx::to_json(doc) << std::endl;
        }
    } catch (const std::exception& e) {
        std::cerr << "Error executing query: " << e.what() << std::endl;
    }

    return 0;
}

```

Facet Example

This query uses the following stages:

- [$search](pipe.$search) to search for companies that include `mobile`
  in the name.

- [$project](manual/reference/operator/aggregation/project) stage to:

  - Include only the specified  fields in the results.

  - Add a field named `score`.

- [$addFields](manual/reference/operator/aggregation/addFields) stage to add the following new fields:

  - A new field named `source` that identifies the collection of the
    output documents.

  - A field name `source_count` that shows a count of the output
    documents.

- [$unionWith](manual/reference/operator/aggregation/unionWith) to do the following:

  - Use [$search](pipe.$search) stage in the sub-pipeline to
    search for inspections of companies that include `mobile`
    in the name.

  - Perform a union of documents from the `companies` and
    documents from the `inspections` collections.

- [$project](manual/reference/operator/aggregation/project) stage to:

  - Include only the specified  fields in the results.

  - Add a field named `score`.

- [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `3` results from
  each collection.

- [$set](manual/reference/operator/aggregation/set) stage to add the following new fields:

  - A new field named `source` that identifies the collection of the
    output documents.

  - A new field named `source_count` that shows a count of the
    output documents.

```cpp
#include <iostream>

#include <bsoncxx/builder/basic/document.hpp>
#include <bsoncxx/builder/basic/array.hpp>
#include <bsoncxx/json.hpp>
#include <mongocxx/client.hpp>
#include <mongocxx/instance.hpp>
#include <mongocxx/uri.hpp>
#include <mongocxx/pipeline.hpp>

using bsoncxx::builder::basic::kvp;
using bsoncxx::builder::basic::make_document;
using bsoncxx::builder::basic::make_array;

int main() {
    // Initialize the MongoDB C++ driver
    mongocxx::instance instance{};

    // Connect to your MongoDB deployment
    mongocxx::uri uri("<connection-string>");
    mongocxx::client client(uri);

    auto db = client["sample_training"];
    auto collection = db["companies"];

    // Build the aggregation pipeline
    mongocxx::pipeline pipeline{};

    // $search stage
    pipeline.append_stage(make_document(
        kvp("$search", make_document(
            kvp("text", make_document(
                kvp("query", "Mobile"),
                kvp("path", "name"),
                kvp("score", make_document(
                    kvp("boost", make_document(
                        kvp("value", 1.6)
                    ))
                ))
            ))
        ))
    ));

    // $project stage
    pipeline.append_stage(make_document(
        kvp("$project", make_document(
            kvp("score", make_document(kvp("$meta", "searchScore"))),
            kvp("_id", 0),
            kvp("number_of_employees", 1),
            kvp("founded_year", 1),
            kvp("name", 1)
        ))
    ));

    // $set stage for source and source_count
    pipeline.append_stage(make_document(
        kvp("$set", make_document(
            kvp("source", "companies"),
            kvp("source_count", "$$SEARCH_META.count.lowerBound")
        ))
    ));

    // $limit stage
    pipeline.append_stage(make_document(
        kvp("$limit", 3)
    ));

    // Create the lookup pipeline for the $unionWith stage
    auto lookup_pipeline = mongocxx::pipeline{};

    lookup_pipeline.append_stage(make_document(
        kvp("$search", make_document(
            kvp("text", make_document(
                kvp("query", "mobile"),
                kvp("path", "business_name")
            ))
        ))
    ));

    lookup_pipeline.append_stage(make_document(
        kvp("$project", make_document(
            kvp("score", make_document(kvp("$meta", "searchScore"))),
            kvp("business_name", 1),
            kvp("address", 1),
            kvp("_id", 0)
        ))
    ));

    lookup_pipeline.append_stage(make_document(
        kvp("$limit", 3)
    ));

    lookup_pipeline.append_stage(make_document(
        kvp("$set", make_document(
            kvp("source", "inspections"),
            kvp("source_count", "$$SEARCH_META.count.lowerBound")
        ))
    ));

    lookup_pipeline.append_stage(make_document(
        kvp("$sort", make_document(
            kvp("score", -1)
        ))
    ));

    // Add $unionWith stage to the main pipeline
    pipeline.append_stage(make_document(
        kvp("$unionWith", make_document(
            kvp("coll", "inspections"),
            kvp("pipeline", lookup_pipeline.view_array())
        ))
    ));

    // Add $facet stage
    pipeline.append_stage(make_document(
        kvp("$facet", make_document(
            kvp("allDocs", make_array()),
            kvp("totalCount", make_array(
                make_document(
                    kvp("$group", make_document(
                        kvp("_id", "$source"),
                        kvp("firstCount", make_document(
                            kvp("$first", "$source_count")
                        ))
                    ))
                ),
                make_document(
                    kvp("$project", make_document(
                        kvp("totalCount", make_document(
                            kvp("$sum", "$firstCount")
                        ))
                    ))
                )
            ))
        ))
    ));

    try {
        // Run the aggregation pipeline and print results
        auto cursor = collection.aggregate(pipeline);

        // Process and print the results
        for (auto&& doc : cursor) {
            std::cout << bsoncxx::to_json(doc) << std::endl;
        }
    } catch (const std::exception& e) {
        std::cerr << "Error executing query: " << e.what() << std::endl;
    }

    return 0;
}

```

