In this section, you can learn how to connect to your deployment and run
the sample query against the indexed collections in the `sample_training` database.

The following query searches both the `companies` and
`inspections` collections for the term `mobile` in the `name`
and `business_name` fields respectively.

Basic Example

This query uses the following stages:

- [$search](pipe.$search) to search for companies that include `mobile`
  in the name.

- [$unionWith](manual/reference/operator/aggregation/unionWith) to do the following:

  - Use [$search](pipe.$search) stage in the sub-pipeline to
    search for inspections of companies that include `mobile`
    in the name.

  - Perform a union of documents from the `companies` and
    documents from the `inspections` collections.

- [$set](manual/reference/operator/aggregation/set) stage to add a new field named `source` that
  identifies the collection of the output documents.

  - [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `3`
    results from each collection.

  - [$project](manual/reference/operator/aggregation/project) stage to:

    - Include only the specified  fields in the results.

    - Add a field named `score`.

```go
const { MongoClient } = require("mongodb");

const agg = [
    {
      '$search': {
        'text': { 'query': 'Mobile', 'path': 'name'  }
      }
    }, {
      '$project': {
        'score': { '$meta': 'searchScore' }, 
        '_id': 0, 'number_of_employees': 1, 'founded_year': 1, 'name': 1
      }
    }, {
      '$set': { 'source': 'companies' }
    }, {
      '$limit': 3
    }, {
      '$unionWith': {
        'coll': 'inspections', 
        'pipeline': [
          {
            '$search': {
              'text': { 'query': 'Mobile', 'path': 'business_name' }
            }
          }, {
            '$set': { 'source': 'inspections' }
          }, {
            '$project': {
              'score': { '$meta': 'searchScore' }, 
              'source': 1, '_id': 0, 'business_name': 1, 'address': 1
            }
          }, {
            '$limit': 3
          }, {
            '$sort': { 'score': -1 }
          }
        ]
      }
    }
  ];

async function run() {
  const client = new MongoClient("<connection-string>");

  try {
    await client.connect();
    const coll = client.db("sample_training").collection("companies");
    const cursor = await coll.aggregate(agg);
    const results = await cursor.toArray();
    console.log(JSON.stringify(results, null, 2));
  } catch (err) {
    console.error("Error:", err);
  } finally {
    await client.close();
  }
}

run().catch(console.dir);

```

Facet Example

This query uses the following stages:

- [$search](pipe.$search) to search for companies that include `mobile`
  in the name.

- [$project](manual/reference/operator/aggregation/project) stage to:

  - Include only the specified  fields in the results.

  - Add a field named `score`.

- [$addFields](manual/reference/operator/aggregation/addFields) stage to add the following new fields:

  - A new field named `source` that identifies the collection of the
    output documents.

  - A field name `source_count` that shows a count of the output
    documents.

- [$unionWith](manual/reference/operator/aggregation/unionWith) to do the following:

  - Use [$search](pipe.$search) stage in the sub-pipeline to
    search for inspections of companies that include `mobile`
    in the name.

  - Perform a union of documents from the `companies` and
    documents from the `inspections` collections.

- [$project](manual/reference/operator/aggregation/project) stage to:

  - Include only the specified  fields in the results.

  - Add a field named `score`.

- [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `3` results from
  each collection.

- [$set](manual/reference/operator/aggregation/set) stage to add the following new fields:

  - A new field named `source` that identifies the collection of the
    output documents.

  - A new field named `source_count` that shows a count of the
    output documents.

```go
const { MongoClient } = require("mongodb");

const agg = [
  {'$search': { 'text': {
    'query': 'mobile', 
    'path': 'name', 
    'score': {
      'boost': { 'value': 1.6 }
    }
  }}}, 
  {'$project': {
    'score': { '$meta': 'searchScore' }, 
    '_id': 0, 
    'number_of_employees': 1, 
    'founded_year': 1, 
    'name': 1
  }}, 
  {'$addFields': {
    'source': 'companies', 
    'source_count': '$$SEARCH_META.count.lowerBound'
  }}, 
  {'$limit': 3}, 
  {'$unionWith': {
    'coll': 'inspections', 
    'pipeline': [
      {'$search': {
        'text': { 'query': 'mobile', 'path': 'business_name' }
      }}, 
      {'$project': {
        'score': { '$meta': 'searchScore' }, 
        'business_name': 1, 
        'address': 1, 
        '_id': 0
      }}, 
      {'$limit': 3}, 
      {'$set': {
        'source': 'inspections', 
        'source_count': '$$SEARCH_META.count.lowerBound'
      }}, 
      {'$sort': { 'score': -1 } }
    ]
  }}, 
  {'$facet': {
    'allDocs': [], 
    'totalCount': [
