In this section, you can learn how to connect to your deployment and run
the sample query against the indexed collections in the `sample_training` database.

The following query searches both the `companies` and
`inspections` collections for the term `mobile` in the `name`
and `business_name` fields respectively.

Basic Example

This query uses the following stages:

- [$search](pipe.$search) to search for companies that include `mobile`
  in the name.

- [$unionWith](manual/reference/operator/aggregation/unionWith) to do the following:

  - Use [$search](pipe.$search) stage in the sub-pipeline to
    search for inspections of companies that include `mobile`
    in the name.

  - Perform a union of documents from the `companies` and
    documents from the `inspections` collections.

- [$set](manual/reference/operator/aggregation/set) stage to add a new field named `source` that
  identifies the collection of the output documents.

  - [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `3`
    results from each collection.

  - [$project](manual/reference/operator/aggregation/project) stage to:

    - Include only the specified  fields in the results.

    - Add a field named `score`.

```go
package main

import (
	"context"
	"fmt"
	"time"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	// connect to your MongoDB deployment and set a maximum operation time
	ctx := context.Background()
	opts := options.Client().
		SetTimeout(5 * time.Second).
		ApplyURI("<connection-string>")

	client, err := mongo.Connect(opts)
	if err != nil {
		panic(err)
	}
	defer client.Disconnect(ctx)

	// set namespace
	collection := client.Database("sample_training").Collection("companies")
	// define pipeline
	searchStage := bson.D{{"$search", bson.D{
		{"text", bson.D{
			{"query", "Mobile"}, {"path", "name"},
		}},
	}}}
	projectStage := bson.D{{"$project", bson.D{
		{"score", bson.D{{"$meta", "searchScore"}}},
		{"_id", 0},
		{"number_of_employees", 1},
		{"founded_year", 1},
		{"name", 1},
	}}}
	setStage := bson.D{{"$set", bson.D{{"source", "companies"}}}}
	limitStage := bson.D{{"$limit", 5}}
	unionWithStage := bson.D{{"$unionWith", bson.D{
		{"coll", "inspections"},
		{"pipeline", bson.A{
			bson.D{{"$search", bson.D{
				{"text", bson.D{
					{"query", "Mobile"}, {"path", "business_name"},
				}},
			}}},
			bson.D{{"$set", bson.D{{"source", "inspections"}}}},
			bson.D{{"$project", bson.D{
				{"score", bson.D{{"$meta", "searchScore"}}},
				{"source", 1},
				{"_id", 0},
				{"business_name", 1},
				{"address", 1},
			}}},
			bson.D{{"$limit", 3}},
			bson.D{{"$sort", bson.D{{"score", -1}}}},
		}},
	}}}
	// run pipeline
	cursor, err := collection.Aggregate(ctx, mongo.Pipeline{searchStage, projectStage, setStage, limitStage, unionWithStage})
	if err != nil {
		panic(err)
	}
	// print results
	var results []bson.D
	if err = cursor.All(context.TODO(), &results); err != nil {
		panic(err)
	}
	for _, result := range results {
		fmt.Println(result)
	}
}

```

Facet Example

