  in the name.

- [$project](manual/reference/operator/aggregation/project) stage to:

  - Include only the specified  fields in the results.

  - Add a field named `score`.

- [$addFields](manual/reference/operator/aggregation/addFields) stage to add the following new fields:

  - A new field named `source` that identifies the collection of the
    output documents.

  - A field name `source_count` that shows a count of the output
    documents.

- [$unionWith](manual/reference/operator/aggregation/unionWith) to do the following:

  - Use [$search](pipe.$search) stage in the sub-pipeline to
    search for inspections of companies that include `mobile`
    in the name.

  - Perform a union of documents from the `companies` and
    documents from the `inspections` collections.

- [$project](manual/reference/operator/aggregation/project) stage to:

  - Include only the specified  fields in the results.

  - Add a field named `score`.

- [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `3` results from
  each collection.

- [$set](manual/reference/operator/aggregation/set) stage to add the following new fields:

  - A new field named `source` that identifies the collection of the
    output documents.

  - A new field named `source_count` that shows a count of the
    output documents.

```go
package main

import (
	"context"
	"fmt"
	"time"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	// connect to your MongoDB deployment and set a maximum operation time
	ctx := context.Background()
	opts := options.Client().
		SetTimeout(5 * time.Second).
		ApplyURI("<connection-string>")

	client, err := mongo.Connect(opts)
	if err != nil {
		panic(err)
	}
	defer client.Disconnect(ctx)
	// set namespace
	collection := client.Database("sample_training").Collection("companies")
	// define pipeline
	searchStage := bson.D{{"$search", bson.D{
		{"text", bson.D{
			{"query", "Mobile"}, {"path", "name"}, {"score", bson.D{{"boost", bson.D{{"value", 1.6}}}}},
		}},
	}}}
	projectStage := bson.D{{"$project", bson.D{
		{"score", bson.D{{"$meta", "searchScore"}}},
		{"_id", 0},
		{"number_of_employees", 1},
		{"founded_year", 1},
		{"name", 1},
	}}}
	addFieldsStage := bson.D{{"$set", bson.D{
		{"source", "companies"},
		{"source_count", "$$SEARCH_META.count.lowerBound"},
	}}}
	limitStage := bson.D{{"$limit", 3}}
	unionWithStage := bson.D{{"$unionWith", bson.D{
		{"coll", "inspections"},
		{"pipeline", bson.A{
			bson.D{{"$search", bson.D{
				{"text", bson.D{
					{"query", "mobile"}, {"path", "business_name"},
				}},
			}}},
			bson.D{{"$project", bson.D{
				{"score", bson.D{{"$meta", "searchScore"}}},
				{"business_name", 1},
				{"address", 1},
				{"_id", 0},
			}}},
			bson.D{{"$limit", 3}},
			bson.D{{"$set", bson.D{
				{"source", "inspections"},
				{"source_count", "$$SEARCH_META.count.lowerBound"},
			}}},
			bson.D{{"$sort", bson.D{{"score", -1}}}},
		}},
	}}}
	facetStage := bson.D{{"$facet", bson.D{
		{"allDocs", bson.A{}},
		{"totalCount", bson.A{
			bson.D{
				{"$group", bson.D{
					{"_id", "$source"},
					{"firstCount", bson.D{{"$first", "$source_count"}}},
				}},
			},
			bson.D{{"$project", bson.D{{"totalCount", bson.D{{"$sum", "$firstCount"}}}}}},
		}},
	}}}
	// run pipeline
	cursor, err := collection.Aggregate(ctx, mongo.Pipeline{searchStage, projectStage, addFieldsStage, limitStage, unionWithStage, facetStage})
	if err != nil {
		panic(err)
	}
	// print results
	var results []bson.D
	if err = cursor.All(context.TODO(), &results); err != nil {
		panic(err)
	}
	for _, result := range results {
		fmt.Println(result)
	}
}

