				"price":    16.68,
				"quantity": 2,
			},
		},
		"storeLocation": "Seattle",
		"customer": bson.M{
			"gender":       "M",
			"age":          50,
			"email":        "keecade@hem.uy",
			"satisfaction": 5,
		},
		"couponUsed":     false,
		"purchaseMethod": "Phone",
	}

	// Insert the documents
	_, err = collection.InsertOne(ctx, purchaseOrder1)
	if err != nil {
		panic(err)
	}

	_, err = collection.InsertOne(ctx, purchaseOrder2)
	if err != nil {
		panic(err)
	}

	fmt.Println("Successfully inserted purchase order documents.")

	// Query the new collection
	findOptions := options.Find().SetSort(bson.D{{Key: "saleDate", Value: -1}})
	cursor, err := collection.Find(ctx, bson.D{}, findOptions)
	if err != nil {
		panic(err)
	}
	defer cursor.Close(ctx)

	// Print results
	var results []bson.M
	if err = cursor.All(ctx, &results); err != nil {
		panic(err)
	}

	fmt.Println("\nQuery results:")
	for _, result := range results {
		fmt.Println(result)
	}
}

sections.body:
In this section, you can learn how to create a materialized view that stores
cumulative sales data for each month. This view uses data from the `sample_supplies.sales`
and `sample_supplies.purchaseOrders` collections. Then, create a function to update
the materialized view each month.

Create a `create_update_view.go` file in your `search-materialized-view` project directory,
and copy and paste the following code into the file. This file performs the following
actions:

- Connects to your MongoDB deployment using the connection string

- Immediately updates the `monthlyPhoneTransactions` materialized view by:

  - Filtering transactions with purchase method of `"Phone"`

  - Unwinding the items array to process each item

  - Grouping transactions by month and year

  - Calculating total sales quantity and price for each month

- Sets up a scheduler that runs on the first day of each month at midnight

- Continues running in the background, automatically refreshing the view on schedule

The materialized view stores aggregated data about phone transactions by month,
which can significantly improve query performance for search operations.

```go
package main

import (
	"context"
	"fmt"
	"log"
	"time"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func updateMonthlyPhoneTransactions(ctx context.Context, client *mongo.Client, collection *mongo.Collection) error {
	// Create the aggregation pipeline
	matchStage := bson.D{bson.E{Key: "$match", Value: bson.D{bson.E{Key: "purchaseMethod", Value: "Phone"}}}}
	unwindStage := bson.D{bson.E{Key: "$unwind", Value: bson.D{bson.E{Key: "path", Value: "$items"}}}}
	groupStage := bson.D{bson.E{Key: "$group", Value: bson.D{
		bson.E{Key: "_id", Value: bson.D{
			bson.E{Key: "$dateToString", Value: bson.D{
				bson.E{Key: "format", Value: "%Y-%m"},
				bson.E{Key: "date", Value: "$saleDate"},
			}},
		}},
		bson.E{Key: "sales_quantity", Value: bson.D{bson.E{Key: "$sum", Value: "$items.quantity"}}},
		bson.E{Key: "sales_price", Value: bson.D{bson.E{Key: "$sum", Value: "$items.price"}}},
	}}}
	setStage := bson.D{bson.E{Key: "$set", Value: bson.D{bson.E{Key: "sales_price", Value: bson.D{bson.E{Key: "$toDouble", Value: "$sales_price"}}}}}}
	mergeStage := bson.D{bson.E{Key: "$merge", Value: bson.D{
		bson.E{Key: "into", Value: "monthlyPhoneTransactions"},
		bson.E{Key: "whenMatched", Value: "replace"},
	}}}

	pipeline := mongo.Pipeline{matchStage, unwindStage, groupStage, setStage, mergeStage}

	// Run the aggregation
	cursor, err := collection.Aggregate(ctx, pipeline)
	if err != nil {
		return err
	}
	defer cursor.Close(ctx)
	return nil
}

func main() {
	// Create a context
	ctx := context.Background()

	// Connect to MongoDB
	uri := "<connection-string>"
	client, err := mongo.Connect(options.Client().ApplyURI(uri))
	if err != nil {
		log.Fatal(err)
	}

	// Ensure the client will be properly disconnected when main exits
	defer func() {
		if err := client.Disconnect(ctx); err != nil {
			log.Fatal(err)
		}
	}()

	// Ping the MongoDB server to verify the connection
	if err := client.Ping(ctx, nil); err != nil {
		log.Fatal(err)
	}

	sales := client.Database("sample_supplies").Collection("sales")
	purchaseOrders := client.Database("sample_supplies").Collection("purchaseOrders")

	// Update immediately on startup
	if err := updateMonthlyPhoneTransactions(ctx, client, sales); err != nil {
		log.Fatal(err)
	}
	if err := updateMonthlyPhoneTransactions(ctx, client, purchaseOrders); err != nil {
		log.Fatal(err)
	}
	fmt.Println("Initial update completed. Materialized view is ready.")

	// Example of a simple scheduler that updates monthly
	dayOfMonth := 1 // Update on the 1st of each month

	for {
		now := time.Now()

		if now.Day() == dayOfMonth && now.Hour() == 0 && now.Minute() == 0 {
			// Create a new context for each update
			updateCtx, cancel := context.WithTimeout(ctx, 30*time.Minute)

			// It's midnight on the 1st of the month - update the view
			if err := updateMonthlyPhoneTransactions(updateCtx, client, sales); err != nil {
				log.Println("Error updating from sales:", err)
			}
			if err := updateMonthlyPhoneTransactions(updateCtx, client, purchaseOrders); err != nil {
				log.Println("Error updating from purchase orders:", err)
			}

			// Cancel the context when done
			cancel()

			fmt.Printf("Scheduled update completed at %s\n", now.Format(time.RFC1123))

			// Sleep for an hour to avoid multiple updates
			time.Sleep(1 * time.Hour)
		} else {
			// Check again in a minute
			time.Sleep(1 * time.Minute)
		}
	}
}

```

Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.

Atlas Cluster

Your connection string should use the following format:

```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```

To learn more, see [Driver](connect-via-driver).

Local or Self-Managed

Your connection string should use the
following format:

```
mongodb://localhost:<port-number>/?directConnection=true
```

To learn more, see [Connection Strings](manual/reference/connection-string).

In your terminal, run the following command to build and run this
application:

**Input:**

```shell
go run create_update_view.go
```

**Output:**

```
Initial update completed. Materialized view is ready.
```

