In this section, you can learn how to create a MongoDB Search index on the `monthlyPhoneTransactions`
collection.

Create a `create-index.js` file in your `search-materialized-view` project directory,
and copy and paste the following code into the file.

```javascript
const { MongoClient } = require("mongodb");

// Replace the connection string with your MongoDB deployment's connection string
const uri =  "<connection-string>";

const client = new MongoClient(uri);

async function run() {
  try {
    const database = client.db("sample_supplies");
    const collection = database.collection("monthlyPhoneTransactions");

    // Create the MongoDB Search index definition
    const index = {
        name: "monthlySalesIndex",
        definition: {
            "mappings": {
